    Log log=new Log("log/singleSignOnV4.log").setIfDisplayTime(true);

    void doTaipeiCityITSingleSignOn( HttpServletRequest request , HttpServletResponse response , HttpSession session , String userId ) throws Exception{
        String apName = Const.AP_DEFAULT;
        //String apName = "testingDB"; //for test
        if( isSessionExist(session) ){ //如果之前已經登入過了，就跳到login頁，讓login頁處理 (Ragic有設定filter，所以這段應該永遠不會進入)
            log.info("login by session!!");
            if(!userId.equals("")) SingleSignOnState.setUserData(userId, ((User)session.getAttribute("USER")).getUserId(),SingleSignOnState.State.SUCCESS);
            else goToLoginPage(response,apName);
            return;
        }else{ //進行sso流程
            SingleSignOnForTaipeiCityGov tpITSso = new SingleSignOnForTaipeiCityGov(response,request); //SingleSignOnForTaipeiCityGov裡面有可能重新導向網頁以及取得cookie，所以需要response和request
            //如果 sso user token失效或不存在的話，doSSO裡面會把網址導向sso server，否則就不會導向
            UserDataForTaipeiCityGov userData = (UserDataForTaipeiCityGov)tpITSso.doSSO();
            log.info("userData:"+(userData != null));
            if( userData != null ){
                String loginAccount = userData.getLoginAccount().orElse(null);
                String userName = userData.getName().orElse(null);
                List<String> deptInfo = userData.getDepartment().orElse(null);
                log.info(loginAccount+","+userName);
                if( loginAccount != null && !loginAccount.isEmpty() ){ //從sso server拿到使用者的登入帳號了
                    //確認帳號
                    if( !isUserExistInAccount( apName , loginAccount) ){ //如果這個使用者帳號沒有在ragic註冊過，那就幫他註冊一個新帳號
                        if( Account.getInstance(apName).ifCanAddUser() ){//確認這個帳號還有剩餘的使用者空間可以讓其增加使用者
                            //此使用者未註冊過，隨機產生一個十位數密碼密碼，並自動註冊新增使用者至資料庫
                            log.info("new user " + loginAccount + " , auto register to Ragic , apName:" + apName);
                            String randomPwd = Encoder.genPassword(10);
                            createNewUser(apName , loginAccount , userName ,randomPwd);
                        }else{
                            log.error("此帳號使用者配額已額滿!");
                        }
                    }else{
                        //此使用者已註冊過
                        changeUserName(loginAccount,userName,apName,session); //把使用者的姓名改成從認證方撈到的姓名，之所以每次登入都要改是因為使用者在認證方是有可能改名的
                        log.info( loginAccount + " have registered on Ragic before ");
                    }
                    //帳號登入
                    if( isUserValidInRagic(loginAccount) ){ //確定使用者已經註冊好(或本來就有)ragic帳號了
                        tpITSso.modifyUserGroup(apName,session,loginAccount,deptInfo,"_");//進入ragic之前先根據使用者職位調整一下使用者的群組
                        if(!userId.equals("")){
                            SingleSignOnState.setUserData(userId,loginAccount,SingleSignOnState.State.SUCCESS);
                            log.info("登入成功:"+userId);
                        }
                        else{
                            loginToRagic(loginAccount,apName,request,response,session);
                        }
                    }else{
                        log.error( loginAccount + " is invalid on Ragic");
                        if(!userId.equals("")) SingleSignOnState.setUserData(userId,null, SingleSignOnState.State.FAILURE);
                    }
                }else{
                    log.error("can't get UserData1");
                    if(!userId.equals(""))  SingleSignOnState.setUserData(userId,null, SingleSignOnState.State.NOUSER);
                    else goToLoginPage(response,apName);
                    return;
                }
            }else {
                log.error("can't get userData2");
                //if(!userId.equals(""))  SingleSignOnState.setUserData(userId,null, SingleSignOnState.State.NOUSER);
                if(userId.equals("")) goToLoginPage(response,apName);
                return;
            }
        }
    }


    boolean isSessionExist(HttpSession session ){
        User user=(User)session.getAttribute("USER");
        return user!=null && user.isValid();
    }

    void goToLoginPage( HttpServletResponse response , String apName ){
        String ragicLoginUrl = "/sims/reg/login.jsp";
        if( apName != null && !apName.isEmpty() )
            ragicLoginUrl+="?a=" + apName;
        try {
            response.sendRedirect(ragicLoginUrl);
        } catch (IOException e) {
            e.printStackTrace();
        }
        return;
    }

    boolean isUserExistInAccount( String apName , String loginAccount ){
        return Account.getInstance(apName).ifHasActiveUser(loginAccount);
    }

    void createNewUser( String apName , String loginAccount , String userName , String randomPwd ){
        int status ;
        status = UserManager.createUser(apName , loginAccount , userName , randomPwd);
        //System.out.println("帳號新增狀態碼:"+status);
    }

    void changeUserName( String loginAccount , String name , String apName , HttpSession session ){
        User user = (User)session.getAttribute("USER");
        RagicBundle bundle = (RagicBundle) session.getAttribute("RAGIC_BUNDLE");
        APIQuery aq = new APIQuery(apName, "/ragic-setup", 1);
        aq.setUpdateMode();
        aq.addFilter(DConst.USER_USERID_EMAIL, "=", loginAccount);
        APIEntry e = aq.getAPIResult();
        System.out.printf("node id : %d\n",e.getRootNodeId());
        e.setFieldValue(DConst.USER_NAME, name);
        e.save(user, bundle);
        Account.getInstance(apName).resetUserInfo();
    }

    boolean isUserValidInRagic( String loginAccount ){
        User registeredUser = RemoteAccountManager.main_userInfo(loginAccount);
        return registeredUser != null && registeredUser.isValid();
    }

    void loginToRagic( String loginAccount , String apName , HttpServletRequest request, HttpServletResponse response , HttpSession session ){
        User user = RemoteAccountManager.main_userInfo(loginAccount);
        if(user!=null){
            user.setIp(request.getRemoteAddr());
            session.setAttribute("USER", user);
            new LoginManager().updateUserLastLogin(user.getUserId(),user.isPassivelyAddedUser());
        }
        goToLoginPage(response , apName);
    }

    JSONObject checkLoginState(HttpServletRequest request) throws JSONException {
        String userId=request.getParameter("userId");
        JSONObject info = new JSONObject();
        log.info("result:"+SingleSignOnState.getUserState(userId).toString());
        info.put("result",SingleSignOnState.getUserState(userId).toString());
        if (SingleSignOnState.getUserState(userId) == SingleSignOnState.State.SUCCESS) {
            //登入API
            String loginAccount= SingleSignOnState.getUserAccount(userId);
            User user= RemoteAccountManager.main_userInfo(loginAccount);//new LoginManager().local_login(email);
            info.put("u",loginAccount);//email
            info.put("apikey",RemoteAccountManager.main_getAPIKey(loginAccount,user.isPassivelyAddedUser()));//apikey
            //登入後釋放userId
            SingleSignOnState.removeUserData(userId);
        //登入失敗?
        }else if(SingleSignOnState.getUserState(userId) == SingleSignOnState.State.FAILURE) {
            SingleSignOnState.removeUserData(userId);
        }
        else if(SingleSignOnState.getUserState(userId) == SingleSignOnState.State.NOUSER) {
            SingleSignOnState.removeUserData(userId);
        }
       return info;
    }

    void setUserIdCookie(HttpServletRequest request,HttpServletResponse response ){
        String userId=request.getParameter("userId");
        log.info("login:"+userId);
        Cookie cookie = new Cookie("userId",userId);
        cookie.setPath("/");
        cookie.setDomain(".gov.taipei");
        cookie.setMaxAge(60*60*24);
        response.addCookie(cookie);
        SingleSignOnState.setUserData(userId,null,SingleSignOnState.State.WAITING);
    }

    String getUserIdFromCookie(HttpServletRequest request){
        String userId="";
        Cookie[] cookies = request.getCookies();
        Cookie cookie_userId = null ;
        if( cookies != null ) {
            cookie_userId= Stream.of(cookies)
                    .filter(cookie -> cookie.getName().equals("userId"))
                    .findFirst().orElse(null);
        }
        if( cookie_userId!=null) {
            userId =  cookie_userId.getValue();
            log.info("useerID from cookie :"+userId);
            return userId;
        }
        return userId;
    }

